CREATE EXTENSION IF NOT EXISTS "uuid-ossp";CREATE TABLE IF NOT EXISTS public.organizations (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name text NOT NULL,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.roles (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,name text NOT NULL,description text,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now(),UNIQUE (organization_id, name));CREATE TABLE IF NOT EXISTS public.users (id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,email text NOT NULL UNIQUE,display_name text,role_id uuid REFERENCES public.roles(id) ON DELETE SET NULL,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.permissions (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name text NOT NULL UNIQUE,description text);CREATE TABLE IF NOT EXISTS public.role_permissions (role_id uuid REFERENCES public.roles(id) ON DELETE CASCADE,permission_id uuid REFERENCES public.permissions(id) ON DELETE CASCADE,PRIMARY KEY (role_id, permission_id));CREATE TABLE IF NOT EXISTS public.suppliers (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,name text NOT NULL,contact_person text,contact_email text,phone text,address text,website text,notes text,risk_assessment jsonb,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.contracts (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,supplier_id uuid NOT NULL REFERENCES public.suppliers(id) ON DELETE RESTRICT,contract_type text NOT NULL,title text NOT NULL,description text,start_date date NOT NULL,end_date date,renewal_date date,value numeric,currency text,payment_terms text,responsible_department text,status text NOT NULL DEFAULT 'Active',auto_renewal_clause boolean DEFAULT FALSE,auto_renewal_period_days integer,termination_notice_days integer,metadata jsonb,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.contract_documents (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),contract_id uuid NOT NULL REFERENCES public.contracts(id) ON DELETE CASCADE,file_name text NOT NULL,file_url text NOT NULL,file_type text,version integer DEFAULT 1,uploaded_by_user_id uuid REFERENCES public.users(id) ON DELETE SET NULL,uploaded_at timestamptz DEFAULT now(),is_main_document boolean DEFAULT FALSE);CREATE TABLE IF NOT EXISTS public.reminders (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,contract_id uuid NOT NULL REFERENCES public.contracts(id) ON DELETE CASCADE,user_id uuid REFERENCES public.users(id) ON DELETE SET NULL,reminder_type text NOT NULL,due_date timestamptz NOT NULL,message text,notification_channels jsonb DEFAULT '[]'::jsonb,is_sent boolean DEFAULT FALSE,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.tasks (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,contract_id uuid REFERENCES public.contracts(id) ON DELETE CASCADE,supplier_id uuid REFERENCES public.suppliers(id) ON DELETE CASCADE,assigned_to_user_id uuid REFERENCES public.users(id) ON DELETE SET NULL,title text NOT NULL,description text,due_date timestamptz,status text NOT NULL DEFAULT 'Pending',priority text DEFAULT 'Medium',created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.communication_logs (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,contract_id uuid REFERENCES public.contracts(id) ON DELETE CASCADE,supplier_id uuid REFERENCES public.suppliers(id) ON DELETE CASCADE,user_id uuid REFERENCES public.users(id) ON DELETE SET NULL,communication_type text NOT NULL,subject text,body text,sent_at timestamptz DEFAULT now(),attachments_url jsonb DEFAULT '[]'::jsonb);CREATE TABLE IF NOT EXISTS public.supplier_performance (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,supplier_id uuid NOT NULL REFERENCES public.suppliers(id) ON DELETE CASCADE,contract_id uuid REFERENCES public.contracts(id) ON DELETE CASCADE,metric_name text NOT NULL,metric_value numeric,target_value numeric,date_recorded date NOT NULL,notes text,created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());CREATE TABLE IF NOT EXISTS public.audit_logs (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,user_id uuid REFERENCES public.users(id) ON DELETE SET NULL,action text NOT NULL,entity_type text NOT NULL,entity_id uuid,old_value jsonb,new_value jsonb,ip_address inet,timestamp timestamptz DEFAULT now());CREATE INDEX idx_contracts_organization_id ON public.contracts(organization_id);CREATE INDEX idx_contracts_supplier_id ON public.contracts(supplier_id);CREATE INDEX idx_contracts_status ON public.contracts(status);CREATE INDEX idx_contracts_renewal_date ON public.contracts(renewal_date);CREATE INDEX idx_suppliers_organization_id ON public.suppliers(organization_id);CREATE INDEX idx_reminders_user_id ON public.reminders(user_id);CREATE INDEX idx_reminders_contract_id ON public.reminders(contract_id);CREATE INDEX idx_tasks_assigned_to_user_id ON public.tasks(assigned_to_user_id);CREATE INDEX idx_audit_logs_organization_id ON public.audit_logs(organization_id);CREATE INDEX idx_audit_logs_user_id ON public.audit_logs(user_id);CREATE INDEX idx_audit_logs_entity ON public.audit_logs(entity_type, entity_id);CREATE OR REPLACE FUNCTION get_user_organization_id() RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER AS $$BEGIN RETURN (SELECT organization_id FROM public.users WHERE id = auth.uid());END;$$;ALTER TABLE public.organizations ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow organization owners to manage organizations" ON public.organizations FOR ALL USING (id IN (SELECT organization_id FROM public.users WHERE id = auth.uid() AND role_id = (SELECT id FROM public.roles WHERE name = 'Organization Owner' AND organization_id = public.organizations.id)));ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to view their own organization's users" ON public.users FOR SELECT USING (organization_id = get_user_organization_id());CREATE POLICY "Allow organization owners to manage users" ON public.users FOR ALL USING (organization_id = get_user_organization_id() AND (SELECT role_id FROM public.users WHERE id = auth.uid()) = (SELECT id FROM public.roles WHERE name = 'Organization Owner' AND organization_id = get_user_organization_id()));ALTER TABLE public.roles ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to view their own organization's roles" ON public.roles FOR SELECT USING (organization_id = get_user_organization_id());CREATE POLICY "Allow organization owners to manage roles" ON public.roles FOR ALL USING (organization_id = get_user_organization_id() AND (SELECT role_id FROM public.users WHERE id = auth.uid()) = (SELECT id FROM public.roles WHERE name = 'Organization Owner' AND organization_id = get_user_organization_id()));ALTER TABLE public.role_permissions ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow organization owners to manage role permissions" ON public.role_permissions FOR ALL USING (role_id IN (SELECT id FROM public.roles WHERE organization_id = get_user_organization_id()) AND (SELECT role_id FROM public.users WHERE id = auth.uid()) = (SELECT id FROM public.roles WHERE name = 'Organization Owner' AND organization_id = get_user_organization_id()));ALTER TABLE public.suppliers ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's suppliers" ON public.suppliers FOR ALL USING (organization_id = get_user_organization_id());ALTER TABLE public.contracts ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's contracts" ON public.contracts FOR ALL USING (organization_id = get_user_organization_id());ALTER TABLE public.contract_documents ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's contract documents" ON public.contract_documents FOR ALL USING (contract_id IN (SELECT id FROM public.contracts WHERE organization_id = get_user_organization_id()));ALTER TABLE public.reminders ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's reminders" ON public.reminders FOR ALL USING (organization_id = get_user_organization_id());ALTER TABLE public.tasks ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's tasks" ON public.tasks FOR ALL USING (organization_id = get_user_organization_id());ALTER TABLE public.communication_logs ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's communication logs" ON public.communication_logs FOR ALL USING (organization_id = get_user_organization_id());ALTER TABLE public.supplier_performance ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to manage their own organization's supplier performance" ON public.supplier_performance FOR ALL USING (organization_id = get_user_organization_id());ALTER TABLE public.audit_logs ENABLE ROW LEVEL SECURITY;CREATE POLICY "Allow users to view their own organization's audit logs" ON public.audit_logs FOR SELECT USING (organization_id = get_user_organization_id());